cat <<'EOF' > /tmp/test_glamour.go
package main

import (
	"fmt"
	"strings"

	"github.com/charmbracelet/glamour"
)

func main() {
	content := "# Hello\n\n## Subheading\n\nSome text with `code`.\n\n- bullet 1\n- bullet 2\n"

	r, err := glamour.NewTermRenderer(
		glamour.WithStandardStyle("dark"),
		glamour.WithWordWrap(80),
	)
	if err != nil {
		fmt.Printf("NewTermRenderer error: %v\n", err)
		return
	}

	out, err := r.Render(content)
	if err != nil {
		fmt.Printf("Render error: %v\n", err)
		return
	}

	fmt.Printf("Rendered output:\n%s\n", out)
	fmt.Printf("Contains ##: %v\n", strings.Contains(out, "##"))
	fmt.Printf("Contains #: %v\n", strings.Contains(out, "#"))
