  1→package checkpoint
  2→
  3→import (
  4→	"encoding/json"
  5→	"sort"
  6→	"strconv"
  7→	"strings"
  8→	"time"
  9→
 10→	"github.com/jcleira/entire-local/pkg/git"
 11→)
 12→
 13→type Loader struct {
 14→	reader *git.Reader
 15→}
 16→
 17→func NewLoader(reader *git.Reader) *Loader {
 18→	return &Loader{reader: reader}
 19→}
 20→
 21→func (l *Loader) ListCheckpoints() ([]CheckpointSummary, error) {
 22→	shards, err := l.reader.ListShards()
 23→	if err != nil {
 24→		return nil, err
 25→	}
 26→
 27→	var summaries []CheckpointSummary
 28→
 29→	for _, shard := range shards {
 30→		rests, err := l.reader.ListCheckpointRests(shard)
 31→		if err != nil {
 32→			continue
 33→		}
 34→
 35→		for _, rest := range rests {
 36→			id := shard + rest
 37→			summary, err := l.loadSummary(id, shard, rest)
 38→			if err != nil {
 39→				continue
 40→			}
 41→			summaries = append(summaries, *summary)
 42→		}
 43→	}
 44→
 45→	sort.Slice(summaries, func(i, j int) bool {
 46→		return summaries[i].CreatedAt.After(summaries[j].CreatedAt)
 47→	})
 48→
 49→	return summaries, nil
 50→}
 51→
 52→func (l *Loader) LoadCheckpoint(id string) (*Checkpoint, error) {
 53→	shard := Shard(id)
 54→	rest := Rest(id)
 55→	prefix := shard + "/" + rest
 56→
 57→	metaJSON, err := l.reader.ReadFile(prefix + "/metadata.json")
 58→	if err != nil {
 59→		return nil, err
 60→	}
 61→
 62→	var meta Metadata
 63→	if err := json.Unmarshal([]byte(metaJSON), &meta); err != nil {
 64→		return nil, err
 65→	}
 66→
 67→	var sessionMeta SessionMetadata
 68→	sessionJSON, err := l.reader.ReadFile(prefix + "/0/metadata.json")
 69→	if err == nil {
 70→		_ = json.Unmarshal([]byte(sessionJSON), &sessionMeta)
 71→	}
 72→
 73→	prompt, _ := l.reader.ReadFile(prefix + "/0/prompt.txt")
 74→	context, _ := l.reader.ReadFile(prefix + "/0/context.md")
 75→	diff, _ := l.reader.ReadFile(prefix + "/0/diff.patch")
 76→	plan, _ := l.reader.ReadFile(prefix + "/0/plan.md")
 77→
 78→	return &Checkpoint{
 79→		Metadata: meta,
 80→		Session:  sessionMeta,
 81→		Prompt:   prompt,
 82→		Context:  context,
 83→		Diff:     diff,
 84→		Plan:     plan,
 85→	}, nil
 86→}
 87→
 88→func (l *Loader) LoadTranscript(id string) ([]TranscriptEntry, error) {
 89→	shard := Shard(id)
 90→	rest := Rest(id)
 91→
 92→	content, err := l.reader.ReadFile(shard + "/" + rest + "/0/full.jsonl")
 93→	if err != nil {
 94→		return nil, err
 95→	}
 96→
 97→	return ParseTranscript(content)
 98→}
 99→
100→func (l *Loader) loadSummary(id, shard, rest string) (*CheckpointSummary, error) {
101→	prefix := shard + "/" + rest
102→
103→	metaJSON, err := l.reader.ReadFile(prefix + "/metadata.json")
104→	if err != nil {
105→		return nil, err
106→	}
107→
108→	var meta Metadata
109→	if err := json.Unmarshal([]byte(metaJSON), &meta); err != nil {
110→		return nil, err
111→	}
112→
113→	summary := &CheckpointSummary{
114→		ID:           id,
115→		Branch:       meta.Branch,
116→		FileCount:    len(meta.FilesTouched),
117→		SessionCount: len(meta.Sessions),
118→		TotalTokens:  meta.TokenUsage.OutputTokens,
119→	}
120→
121→	var sessionMeta SessionMetadata
122→	sessionJSON, err := l.reader.ReadFile(prefix + "/0/metadata.json")
123→	if err == nil {
124→		if json.Unmarshal([]byte(sessionJSON), &sessionMeta) == nil {
125→			summary.Agent = sessionMeta.Agent
126→			summary.AgentPercent = int(sessionMeta.Attribution.AgentPercentage)
127→			createdAt, _ := time.Parse(time.RFC3339, sessionMeta.CreatedAt)
128→			if createdAt.IsZero() {
129→				createdAt, _ = time.Parse(time.RFC3339Nano, sessionMeta.CreatedAt)
130→			}
131→			summary.CreatedAt = createdAt
132→		}
133→	}
134→
135→	if summary.SessionCount == 0 {
136→		entries, err := l.reader.ListEntries(prefix)
137→		if err == nil {
138→			for _, name := range entries {
139→				if _, err := strconv.Atoi(name); err == nil {
140→					summary.SessionCount++
141→				}
142→			}
143→		}
144→	}
145→
146→	prompt, err := l.reader.ReadFile(prefix + "/0/prompt.txt")
147→	if err == nil {
148→		summary.Prompt = prompt
149→	}
150→
151→	context, err := l.reader.ReadFile(prefix + "/0/context.md")
152→	if err == nil {
153→		summary.Context = context
154→	}
155→
156→	diff, err := l.reader.ReadFile(prefix + "/0/diff.patch")
157→	if err == nil {
158→		_, adds, dels := parseDiffStats(diff)
159→		summary.Additions = adds
160→		summary.Deletions = dels
161→	}
162→
163→	if !summary.CreatedAt.IsZero() && meta.Branch != "" {
164→		info, err := l.reader.FindCommitBefore(meta.Branch, summary.CreatedAt.Add(10*time.Second))
165→		if err == nil {
166→			summary.CommitMessage = info.Subject
167→			summary.CommitHash = info.Hash
168→			summary.Author = info.Author
169→			adds, dels, err := l.reader.DiffStats(info.Hash)
170→			if err == nil && (adds > 0 || dels > 0) {
171→				summary.Additions = adds
172→				summary.Deletions = dels
173→			}
174→		}
175→	}
176→
177→	return summary, nil
178→}
179→
180→func Shard(id string) string {
181→	if len(id) < 2 {
182→		return id
183→	}
184→	return id[:2]
185→}
186→
187→func Rest(id string) string {
188→	if len(id) <= 2 {
189→		return ""
190→	}
191→	return id[2:]
192→}
193→
194→func parseDiffStats(diff string) (files, adds, dels int) {
195→	filesSeen := make(map[string]bool)
196→	for _, line := range strings.Split(diff, "\n") {
197→		if strings.HasPrefix(line, "diff --git") {
198→			parts := strings.Fields(line)
199→			if len(parts) >= 4 {
200→				filesSeen[parts[3]] = true
201→			}
202→		} else if strings.HasPrefix(line, "+") && !strings.HasPrefix(line, "+++") {
203→			adds++
204→		} else if strings.HasPrefix(line, "-") && !strings.HasPrefix(line, "---") {
205→			dels++
206→		}
207→	}
208→	files = len(filesSeen)
209→	return
210→}
