131→type fileDiffStat struct {
132→	name string
133→	add  int
134→	del  int
135→}
136→
137→type diffStatsResult struct {
138→	files    []fileDiffStat
139→	totalAdd int
140→	totalDel int
141→}
142→
143→func parseDiffStats(diff string) diffStatsResult {
144→	var result diffStatsResult
145→	if diff == "" {
146→		return result
147→	}
148→
149→	var current *fileDiffStat
150→	for _, line := range strings.Split(diff, "\n") {
151→		if strings.HasPrefix(line, "diff --git") {
152→			if current != nil {
153→				result.files = append(result.files, *current)
154→			}
155→			parts := strings.Fields(line)
156→			name := ""
157→			if len(parts) >= 4 {
158→				name = strings.TrimPrefix(parts[3], "b/")
159→			}
160→			current = &fileDiffStat{name: name}
161→		} else if current != nil {
162→			if strings.HasPrefix(line, "+") && !strings.HasPrefix(line, "+++") {
163→				current.add++
164→			} else if strings.HasPrefix(line, "-") && !strings.HasPrefix(line, "---") {
165→				current.del++
166→			}
167→		}
168→	}
169→	if current != nil {
170→		result.files = append(result.files, *current)
171→	}
172→
173→	for _, f := range result.files {
174→		result.totalAdd += f.add
175→		result.totalDel += f.del
176→	}
177→
178→	return result
179→}
