245→func wordWrap(text string, width int) string {
246→	if width <= 0 {
247→		return text
248→	}
249→	var result strings.Builder
250→	for _, line := range strings.Split(text, "\n") {
251→		if len(line) <= width {
252→			result.WriteString(line + "\n")
253→			continue
254→		}
255→		remaining := line
256→		for len(remaining) > width {
257→			breakAt := width
258→			if idx := strings.LastIndex(remaining[:width], " "); idx > 0 {
259→				breakAt = idx
260→			}
261→			result.WriteString(remaining[:breakAt] + "\n")
262→			remaining = strings.TrimLeft(remaining[breakAt:], " ")
263→		}
264→		if remaining != "" {
265→			result.WriteString(remaining + "\n")
266→		}
267→	}
268→	return strings.TrimRight(result.String(), "\n")
269→}
