 50→func (r *Reader) FindCommitBefore(branch string, before time.Time) (CommitInfo, error) {
 51→	out, err := ExecGit(r.repoRoot, "log", branch, "--format=%H%x09%s%x09%an", "-1", "--before="+before.Format(time.RFC3339))
 52→	if err != nil {
 53→		return CommitInfo{}, err
 54→	}
 55→	if out == "" {
 56→		return CommitInfo{}, fmt.Errorf("no commit found before %s", before)
 57→	}
 58→	parts := strings.SplitN(out, "\t", 3)
 59→	if len(parts) < 3 {
 60→		return CommitInfo{}, fmt.Errorf("unexpected log format: %s", out)
 61→	}
 62→	return CommitInfo{
 63→		Hash:    parts[0],
 64→		Subject: parts[1],
 65→		Author:  parts[2],
 66→	}, nil
 67→}
