 69→func (r *Reader) DiffStats(hash string) (adds, dels int, err error) {
 70→	out, err := ExecGit(r.repoRoot, "diff", "--numstat", hash+"~1", hash)
 71→	if err != nil {
 72→		return 0, 0, nil
 73→	}
 74→	for _, line := range strings.Split(out, "\n") {
 75→		if line == "" {
 76→			continue
 77→		}
 78→		fields := strings.Fields(line)
 79→		if len(fields) < 2 {
 80→			continue
 81→		}
 82→		a, _ := strconv.Atoi(fields[0])
 83→		d, _ := strconv.Atoi(fields[1])
 84→		adds += a
 85→		dels += d
 86→	}
 87→	return adds, dels, nil
 88→}
