212→func formatTimeAgo(t time.Time) string {
213→	if t.IsZero() {
214→		return ""
215→	}
216→	d := time.Since(t)
217→	switch {
218→	case d < time.Minute:
219→		return "just now"
220→	case d < time.Hour:
221→		m := int(d.Minutes())
222→		return fmt.Sprintf("%dm ago", m)
223→	case d < 24*time.Hour:
224→		h := int(d.Hours())
225→		return fmt.Sprintf("%dh ago", h)
226→	default:
227→		days := int(d.Hours() / 24)
228→		return fmt.Sprintf("%dd ago", days)
229→	}
230→}
